window.__QUIZ_DATA__=[{"id":"objective>Mathematics>1999>1","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : SURDS -RADICALS","question":"Evaluate \u221a20 x (\u221a5)3","images":[],"options":{"A":"10","B":"20","C":"25","D":"50"},"answer":"D","explanation":"\u221a20 x (\u221a5)3 = \u221a20 x \u221a5 x \u221a5 x \u221a5    Recall: \u221aa x \u221ab = \u221aab    = \u221a(20 x 5) x \u221a(5 x 5) = \u221a100 x \u221a25    = 10 x 5 = 50","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>2","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"If P = {3, 7, 11, 13} and Q = {2, 4, 8, 16}, which of the following is correct?","images":[],"options":{"A":"(P \u22c2 Q)1 = {2, 3, 4, 13}","B":"n(P \u22c3 Q) = 4","C":"P \u22c3 Q = \u2205","D":"P \u22c2 Q = \u2205"},"answer":"D","explanation":"P = {3, 7, 11, 13}; Q = {2, 4, 8, 16}  Since no universal set is given as reference; then we cannot find (P \u22c2 Q)1.  (P \u22c3 Q) = {2, 3, 4, 7, 8, 11, 13, 16}  Hence n(P \u22c3 Q) = 8 not 4.  P \u22c3 Q = \u2205 is not correct.  \u2234 P \u22c2 Q = \u2205  is the only correct statement","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1999>3","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"It is observed that: 1 + 3 = 22 ; 1 + 3 + 5 = 32; 1 + 3 + 5 + 7 = 42.  If 1 + 3 + 5 + 7 + 9 + 11 + 13 + 15 = P2, find P2","images":[],"options":{"A":"6","B":"7","C":"8","D":"9"},"answer":"C","explanation":"1 + 3 = 22; 1 + 3 + 5 = 32; 1 + 3 + 5 + 7 = 42  From these we observe that the number with square is the middle value of the numbers on the left.  \u2234 If 1 + 3 + 5 + 7 + 9 + 11 + 13 + 15 = P2; P is therefore the middle value  P=(7 + 9)2=8","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>4","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBERS IN STANDARD FORM-SCIENTIFIC NOTATION","question":"Evaluate 3.0 x 101 - 2.8 x 10-1","images":[],"options":{"A":"2 x 10-1","B":"2 x 102","C":"2.972 x 101","D":"2.972 x 102"},"answer":"C","explanation":"3.0x101-2.8x10-1=30- (2.8x110) =30-0.28=29.72  \u223429.72=2.972x101","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1999>5","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"A trader makes a loss of 15% when selling article, find the ratio, selling price : cost price","images":[],"options":{"A":"3 : 20","B":"3 : 17","C":"17 : 20","D":"20 : 23"},"answer":"C","explanation":"If a trader makes a loss of 15% when selling i.e selling price  \u2234 Selling price = 100% - 15% = 85%  Cost price = 100%  \u2234 Ratio of selling price to cost price = 85 : 100 = 17 : 20 (when you reduce to the lowest term)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>6","subject":"Mathematics","year":"1999","type":"Objective","topic":"MENSURATION : AREAS","question":"The side of a square is increased from 20 cm to 21 cm. Calculate the percentage increase in its area.","images":[],"options":{"A":"2.5%","B":"9.3%","C":"10.0%","D":"10.25%"},"answer":"D","explanation":"New side = 21 cm  New area = 21 x 21 = 441 cm2  Initial side = 20 cm  Initial area = 20 x 20 = 400 cm2  \u2234increaseinarea=441 - 400400=41400x1001=10.25%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>7","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Arrange in ascending order of magnitude: 268, 367 and 259.","images":[],"options":{"A":"259, 268, 367","B":"268, 259, 367","C":"367, 268, 259","D":"367, 259, 268"},"answer":"B","explanation":"268 = 2 x 8 + 6 = 16 + 6 = 22  367 = 3 x 7 + 6 = 21 + 6 = 27  259 = 2 x 9 + 5 = 18 + 5 = 23  \u2234 in ascending order of magnitude = 268, 259, 367","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>8","subject":"Mathematics","year":"1999","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"The side of a rhombus is 10 cm long, correct to the nearest whole number, between what limits should the perimeter P lie?","images":[],"options":{"A":"39 cm \u2264 P \u2264 41 cm","B":"38 cm \u2264 P","C":"38.5 cm \u2264 P","D":"38.5 cm \u2264 P \u2264 40 cm"},"answer":"B","explanation":"10 cm to the nearest whole number means values can lie within the range 9.5 cm ~ 10.5 cm.  A rhombus has four equal sides.  \u2234 Perimeter = 4s where s stands for length of each side.  \u2234 Range of perimeter = 4(9.5 cm) ~ 4(10.5 cm) = 38 cm \u2264 P","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>9","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Simplify log78 - log72 + log74","images":[],"options":{"A":"0","B":"2log72","C":"3log72","D":"4log72"},"answer":"D","explanation":"log78 - log72 + log74    Recall logaX - logaY = loga(X/Y) and logaX + logaY = loga(XY)    \u2234 log78 - log72 + log74 =log7(8/2 x 4) = log716    Recall logaXn = nlogaX    \u2234 log716 = log724 = 4log72","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>10","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : SURDS -RADICALS","question":"if K\u221a28 + \u221a63 - \u221a7 = 0, find K.","images":[],"options":{"A":"-2","B":"-1","C":"1","D":"2"},"answer":"B","explanation":"K\u221a28 + \u221a63 - \u221a7 = 0  K(\u221a7 x \u221a4) + (\u221a7 x \u221a9) - \u221a7 = 0  K(\u221a7 x 2) + (\u221a7 x 3) - \u221a7 = 0  K(2\u221a7) + (3\u221a7) - \u221a7 = 0  2K\u221a7 + 3\u221a7 - \u221a7 = 0  2K\u221a7 + 2\u221a7 = 0  2K\u221a7 = -2\u221a7  K\u221a7 = -\u221a7  Divide both sides by \u221a7  \u2234 K = -1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>11","subject":"Mathematics","year":"1999","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"From the set A = {3, \u221a2, 2\u221a3, \u221a9, \u221a7}, a number is selected at random. Find the probability that it is a rational number.","images":[],"options":{"A":"1/5","B":"2/5","C":"3/5","D":"4/5"},"answer":"B","explanation":"A = {3, \u221a2, 2\u221a3, \u221a9, \u221a7}  Rational numbers are integers or fractions positive or negative.  A = {3, \u221a2, 2\u221a3, \u221a9, \u221a7} = {3, \u221a2, 2\u221a3, \u22133, \u221a7}  Rational numbers are 3, -3  \u2234 Probability of rational numbers = 2/5","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1999>12","subject":"Mathematics","year":"1999","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The pie chart illustrate the amount of private time a student spends in a week studying various subjects.  Use it to answer Questions below    Find the value of k.","images":["data:image/png;base64,"],"options":{"A":"15o","B":"30o","C":"60o","D":"90o"},"answer":"B","explanation":"In a pie chart, sum of all angles = 360o  \u2234 105o + 75o + 3K + K + 2K = 360o  180o + 6K = 360o  6K = 360o - 180o  6K = 180o  K = 30o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>13","subject":"Mathematics","year":"1999","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The pie chart illustrate the amount of private time a student spends in a week studying various subjects.  Use it to answer Questions below  If he spends 21/2 hours a week on science, find the total number of hours he studies a week.","images":["data:image/png;base64,"],"options":{"A":"31/2 hours","B":"5 hours","C":"8 hours","D":"12 hours"},"answer":"D","explanation":"Fractiononscience=75360  Hoursonscience=21/2hours  Letx=totalhours  \u223475x360=21/2;75x360=52  150x=1800  x=12hours","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>14","subject":"Mathematics","year":"1999","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A group of 11 people can speak either English or French or both. Seven can speak English and six can speak French. What is the probability that a person chosen at random can speak both English and French?","images":[],"options":{"A":"2/11","B":"4/11","C":"5/11","D":"11/13"},"answer":"A","explanation":"n(E \u22c3 F) = 11; n(E) = 7; n(F) = 6; n(E \u22c2 F) = ?  n(E \u22c3 F) = n(E) + n(F) - n(E \u22c2 F)  11 = 7 + 6 - n(E \u22c2 F)  11 = 13 - n(E \u22c2 F)  n(E \u22c2 F) = 13 - 11 = 2  \u2234 Probability of choosing at random a student that can speak both English and French = 2/11","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>15","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"The interior angle of a regular polygon is twice the exterior angle. How many sides has the polygon?","images":[],"options":{"A":"5","B":"6","C":"8","D":"9"},"answer":"B","explanation":"Let each interior angle = 2x  \u2234 Each exterior angle = x  The sum of each interior angle and an adjacent exterior angle = 180o  \u2234 2x + x = 180o  3x = 180o  x = 60o  \u2234 Each interior angle of the polygon = 120o  Let the sides of the polygon = n  \u2234 (2n - 4)90o = 120n  180n - 360o = 120n  180n - 120n = 360o  60n = 360o  \u2234 n = 6","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>16","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Which one of the following figures has one line of symmetry only?  I. isosceles triangle II. Rhombus III. Kite","images":[],"options":{"A":"I and II only","B":"II and III only","C":"I and III only","D":"I, II and III"},"answer":"C","explanation":"An isosceles triangle has only one symmetry  A kite has only one line of symmetry  A rhombus has 4 lines of symmetry","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>17","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram below, |XR| = |RY| = |YZ| and \u2220XRY = \u2220YRZ = 62o. Calculate \u2220XYZ","images":["data:image/png;base64,"],"options":{"A":"50o","B":"62o","C":"112o","D":"115o"},"answer":"D","explanation":"\u2220XRY+\u2220RYX+\u2220RXY=180o(sumofanglesinatriangle)  \u2220X=\u2220Y(baseanglesofanisoscelestriangle)  62o+2x=180o  x=1182=\u2220X=\u2220Y=59o  \u2220Z=62o\u2234\u2220RYZ=180o-(2x62)  =180o-124o=56o  But\u2220XYZ=\u2220RYZ=59o+56o=115o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>18","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, RST is a tangent to VSU centre O, \u2220SVU = 50o and UV is a diameter, calculate \u2220 RSV.","images":["data:image/png;base64,"],"options":{"A":"60o","B":"50o","C":"45o","D":"40o"},"answer":"D","explanation":"\u2220RSV = \u2220SUV (the angle between a chord and a tangent at the point of contact is the angle in the opposite segment)  \u2220VSU = 90o (angle in a semi circle is a right angle)  \u2220V + \u2220VSU + \u2220U = 180o (sum of angles in a triangle)  50o + 90o + U = 180o  140o + U = 180o  U = 180o - 140o = 40o  \u2234 \u2220RSV = U = 40o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>19","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Calculate the value of y from the diagram.","images":["data:image/png;base64,"],"options":{"A":"18o","B":"42o","C":"48o","D":"132o"},"answer":"C","explanation":"\u2220HEF + \u2220DEH = 180o (sum of angles on a straight line)  \u2220HEF + 123o = 180o  \u2220HEF = 180o - 123o = 57o  \u2220CBF = \u2220GFH = 105o (corresponding angles are equal)  \u2220HFE + \u2220GFH = 180o (sum of angles on a straight line)  \u2220HFE + 105o  = 180o  \u2220HFE = 180 - 105o = 75o  From \u2206EHF  \u2220HFE + \u2220HEF + \u2220EHF = 180o (sum of angles in a triangle)  75o + 57o + y = 180o  132o + y = 180o  y = 180o - 132o  \u2234 y = 48o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>20","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagam, PQR is a circle with centre O. \u2220QRP = 50o, \u2220PQO = 30o and \u2220ORP = m. Find m.","images":["data:image/png;base64,"],"options":{"A":"20o","B":"25o","C":"30o","D":"50o"},"answer":"A","explanation":"Construction: Join OP   then \u2220OPQ = 30o (base angles of issoceles \u2206QPR)  But \u2220OPR = m (base angles of issoceles \u2206OPR)  But \u2220QPR = \u2220OPQ + \u2220OPR  50o = 30o + \u2220OPR  \u2220OPR = 50o - 30o  \u2234\u2220OPR = 20o  But \u2220OPR = \u2220ORP = m  \u2234 m = 20o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>21","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Giventhatm=-3andn=2,findthevalueof3n2 - 2m3m","images":[],"options":{"A":"-22","B":"-14","C":"14","D":"22"},"answer":"A","explanation":"If m = -3 and n = 2; \u22343n2 - 2m3m = 3(2)2 - 2(-3)3-3  = 3 x 4 - (2 x -27)-3 = 12 + 54-3  = 66-3 = -22","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>22","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify2 - 18m21 + 3m","images":[],"options":{"A":"2(1 + 3m)","B":"2(1 - 3m)","C":"2(1 + 3m2)","D":"2(1 - 3m2)"},"answer":"B","explanation":"2 - 18m21 + 3m = 2(1 - 9m2)1 + 3m=2(12 - (3m)2)1 + 3m = 2(1 - 3m)(1 + 3m)1 + 3m = 2(1 - 3m)","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1999>23","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"If y = \u221a(ax - b), express x in terms of y, a and b.","images":[],"options":{"A":"x=y2 - ba","B":"x=y + ba","C":"x=y - ba","D":"x=y2 + ba"},"answer":"D","explanation":"y = \u221a(ax - b)  Square both sides  \u2234 y2 = ax - b  y2 + b = ax  Divide both sides by a  \u2234x=y2 + ba","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>24","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Given that 81 x 22n - 2 = K, find \u221aK","images":[],"options":{"A":"4.5 x 2n","B":"4.5 x 22n","C":"9 x 2n - 1","D":"9 x 22n"},"answer":"A","explanation":"81x22n - 2=K ==>81x22nx2-2=K ==>81x22nx122=K  = 81x22nx14=K ==> 814 x 22n = K ==> 9222 x (2n)2 = K ==> (92)2 x (2n)2 = K  =  (92 x 2n)2 = K  \u2234 \u221aK =92 x 2n = 4.5 x 2n","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>25","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify4x + 1-3x - 1","images":[],"options":{"A":"x + 7x2 - 1","B":"x - 1x2 + 1","C":"x - 7x2 - 1","D":"x - 11x2 - 1"},"answer":"C","explanation":"4x + 1-3x - 1  4(x - 1) - 3(x + 1)(x + 1)(x - 1)  4x - 4 - 3x - 3x2 - 1  x - 7x2 - 1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>26","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"If y varies inversely as x2, how does x vary with y?","images":[],"options":{"A":"x varies inversely as y2","B":"x varies inversely as \u221ay","C":"x varies directly as y2","D":"x varies directly as \u221ay"},"answer":"B","explanation":"yvariesinverselyasx2  =y\u221d1x2\u2234 x2y\u221d1  =x2\u221d1y\u2234x\u221d1\u221ay","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>27","subject":"Mathematics","year":"1999","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If tan x = 1/\u221a3, find cos x - sin x, such that 0 \u2264 \u03b8 \u2264 90o","images":[],"options":{"A":"\u221a3 + 12","B":"2\u221a3 + 1","C":"\u221a3 - 12","D":"2\u221a3 - 1"},"answer":"C","explanation":"In\u2206PQR,tanx=1\u221a3  Usingpythagorastheorem:  PQ2+QR2=PR2  12+(\u221a3)2=PR2  1+3=PR2  PR2=4==>PR=2  cosx=adjhyp=\u221a32  sinx=opphyp=12  \u2234cosx-sinx=\u221a32-12=\u221a3 - 12","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>28","subject":"Mathematics","year":"1999","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"From the top of a tree 20 m high, a boat can be sighted at sea 75 m from the foot of the cliff. Calculate the angle of depression of the boat from the top of the cliff.","images":[],"options":{"A":"14.9o","B":"15.5o","C":"74.5o","D":"75.1o"},"answer":"A","explanation":"If \u03b1 is the angle of depression  \u2234 \u2220ABC = \u03b1 (alternate angles are equal)  \u2234 tan \u03b1 = tan-1 0.2667  \u2234 \u03b1 = 14.9o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>29","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"From the diagram below, ABC is a triangle inscribed in a circle centre O. \u2220ACB = 40o and |AB| = x cm. Calculate the radius of the circle.","images":["data:image/png;base64,"],"options":{"A":"xsin 40o","B":"xcos 40o","C":"x2 sin 40o","D":"x2 cos 40o"},"answer":"C","explanation":"Usingsinerule  asin A=bsin B=csin C=2R (/AC/)sin 90o(angle in a semi-circle is a right angle)  \u2234ABsin 40o=2R\u2234 R=x2sin 40o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>30","subject":"Mathematics","year":"1999","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"The diagram shows the position of the three ships A, B and C at sea. B is due north of C such that |AB| = |BC| and the bearing of B from A = 040o. What is the bearing of A from C?","images":["data:image/png;base64,"],"options":{"A":"040o","B":"070o","C":"110o","D":"290o"},"answer":"D","explanation":"The bearing of A from C = Reflex angle BCA  =180o+\u03b1\u2234\u2220ABCAB=40oBC (alternate angles)  \u2234 \u2220BAC = \u2220ACB (base angles of isosceles triangle)  But \u2220ABC + \u2220BAC + \u2220ACB = 180o (sum of angles in a triangle)  40o + 2\u2220BAC = 180o  2\u2220BAC = 180o - 40o = 140o   \u2220BAC = 70o  \u2234 The exterior angle of \u2220ACB = 180o - 70o = 110o  Bearing of A from C = 180o + 110o = 290o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>31","subject":"Mathematics","year":"1999","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"A pole of length L leans against a vertical wall so that it makes an angle 60o with the horizontal ground. If the top of the pole is 8 m above the ground, calculate L.","images":[],"options":{"A":"16\u221a3 m","B":"4\u221a3 m","C":"\u221a316m","D":"16\u221a33m"},"answer":"D","explanation":"Inthetriangle,sin60o=8L  \u2234Lsin60=8;L=8sin60o  L=8\u221a3/2=16\u221a3  = 16 x \u221a3\u221a3 x \u221a3=16\u221a33 m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>32","subject":"Mathematics","year":"1999","type":"Objective","topic":"MENSURATION : AREAS","question":"In the diagram, PQST and QRST are parallelograms. Calculate the area of the trapezium PRST.","images":["data:image/png;base64,"],"options":{"A":"60 cm2","B":"50 cm2","C":"40 cm2","D":"30 cm2"},"answer":"D","explanation":"SinceTS=4cm  \u2234PQ=4cm(oppositesidesofaparallelogram)  QR=4cm(oppositesideofrectangleQRST)  \u2234PR=PQ+QR=4cm+4cm=8cm  AreaoftrapeziumPRST=12(a + b)h  wherea=8cm;b=4cmandh=5cm.  A=12(8 + 4)5 =30cm2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>33","subject":"Mathematics","year":"1999","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The height of a pyramid on a square base is 15 cm. If the volume is 80 cm3, find the length of the side of the base.","images":[],"options":{"A":"3.3 cm","B":"5.3 cm","C":"4.0 cm","D":"8.0 cm"},"answer":"C","explanation":"Volume of pyramid = 1/3 x base area x height    \u2234 80 cm3 = 1/3 x A x 15    80 = 5A    A = 16 cms    \u2234 Side of base = \u221a16 = 4.0 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>34","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBERS IN STANDARD FORM-SCIENTIFIC NOTATION","question":"Simply 3.72 x 0.025 and express your answer in the standard form.","images":[],"options":{"A":"9.3 x 103","B":"9.3 x 102","C":"9.3 x 10-2","D":"9.3 x 10-3"},"answer":"C","explanation":"3.72 x 0.025 = 3.72 x 10o x 2.5 x 10-2  = 3.72 x 2.5 x 10-2  = 9.3 x 10-2","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1999>35","subject":"Mathematics","year":"1999","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Two numbers 24x , and 31y are equal in value when converted to base 10. Find the equation connecting x and y.","images":[],"options":{"A":"2x = 3(y - 1)","B":"4x - y = 1","C":"3y + 2x = 3","D":"3y = 2(x + 3)"},"answer":"A","explanation":"24x = 31y  ==> 2x + 4 = 3y + 1  2x = 3y + 1 - 4  2x = 3y - 3  \u2234 2x = 3(y - 1)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>36","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"A car travels at x km per hour for 1 hour and at y km per hour for 2 hours. Find its average speed.","images":[],"options":{"A":"2x + 2y3 kmhr-1","B":"x + y3 kmhr-1","C":"x + 2y3 kmhr-1","D":"2x + y3 kmhr-1"},"answer":"C","explanation":"x km/hr for 1 hour and y km/hr for 2 hours.  Total distance travelled = x km + y km  Total time spent = 1 + 2 = 3 hours  Averagespeed=Total distanceTotal time=x + 2y3 kmhr-1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>37","subject":"Mathematics","year":"1999","type":"Objective","topic":"MENSURATION : AREAS","question":"The height and base of a triangle are in the ratio 1 : 3 respectively. If the area of the triangle is 216 cm2. Find the length of the base.","images":[],"options":{"A":"24 cm","B":"36 cm","C":"72 cm","D":"144 cm"},"answer":"B","explanation":"h : b = 1 : 3    Let the height = x \u2234 base = 3x    Area of triangle = 1/2 bh = 216 cm2    1/2. x . 3x = 216    1/2. 3x2 = 216    3x2 = 432    x2 = 144    x = 12 cm    \u2234 Length of base = 3 x 12 = 36 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>38","subject":"Mathematics","year":"1999","type":"Objective","topic":"MENSURATION : VOLUMES","question":"Water flows from a top into a cylindrical container at the rate of 5\u03c0 cm3 per second. If the radius of the container is 3 cm, calculate the level of water in the container at the end of 9 seconds.","images":[],"options":{"A":"2 cm","B":"5 cm","C":"8 cm","D":"15 cm"},"answer":"B","explanation":"rate = 5\u03c0 cm3/s  After 9 sec; Volume = 5\u03c0 x 9 = 45\u03c0 cm3  If the height of the container = h  \u2234 Volume = \u03c0r2h  \u2234 \u03c0 x 32 x h = 45\u03c0; 9h = 45  \u2234 h = 5 cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>39","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Amina had m mangoes. She ate 3 and shared the remainder equally with her brother Uche. Each had at least 10. Which of the following inequalities represents the statements above?","images":[],"options":{"A":"m2-3\u226410","B":"m2-3\u226510","C":"m - 32\u226510","D":"m - 32\u226410"},"answer":"C","explanation":"Total number of mangoes = m  She ate 3 \u2234 number of remaining mango = m - 3.  remaining was shared into 2  \u2234m - 32isat least10  \u2234m - 32\u226510","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>40","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Which of the following pairs of inequalities is represented on the number line?","images":["data:image/png;base64,"],"options":{"A":"x","B":"x \u2264 -2 and x > 1","C":"x \u2264 -2 and x \u2265 1","D":"x  1"},"answer":"C","explanation":"Since the dots are shaded    \u2234 x \u2264 -2 and x \u2265 1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>41","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"If x2 + 15x + 50 = ax2 + bx + c = 0, which of the following statements is not true?","images":[],"options":{"A":"x = -5","B":"x = 10","C":"x + 10 = 0","D":"bc = 750"},"answer":"B","explanation":"x2 + 15x + 50 = ax2 + bx + c = 0  Factorising: (x + 10)(x + 5) = ax2 + bx + c  x + 10 = 0 or x + 5 = 0  x = -10 or x = -5  since b = 15 and c = 50  \u2234 bc = 750  \u2234 x = 10 is not true","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>42","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"The roots of a quadratic equation in x, are -m and 2n. Find the equation.","images":[],"options":{"A":"x2 + x(m - 2n) - 2mn = 0","B":"x2 - x(m - 2n) - 2mn = 0","C":"x2 - x(2n - m) + 2mn = 0","D":"x2 + x(m - 2n) + 2mn = 0"},"answer":"A","explanation":"Roots are -m and 2n  \u2234 Equation ==> (x + m)(x - 2n) = 0  x2 - 2nx + mx - 2mn = 0  x2 + x(m - 2n) - 2mn = 0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>43","subject":"Mathematics","year":"1999","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A survey shows that 28% of all the men in a village wear size 9 shoes. What is the probability that  man selected at random in the village wears size 9 shoes?","images":[],"options":{"A":"7/25","B":"41/50","C":"1/2","D":"1"},"answer":"A","explanation":"Percentage=28%  Probabilityofsize9shoes=28100=725","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1999>44","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Solve the inequality 2x + 3","images":[],"options":{"A":"x > 1","B":"x 3/7","C":"x > 3/7","D":"x > -1"},"answer":"A","explanation":"2x + 3  Collect like terms  2x - 5x  -3x  \u2234 x > 1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>45","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the diagram, DE||BC, |AD| = x cm and |DB| = |AE| = y cm. Find |CE| in terms of x and y.","images":["data:image/png;base64,"],"options":{"A":"x","B":"x2y","C":"yx2","D":"y2x"},"answer":"D","explanation":"Usingsimilartriangles  DAAE=ABAC\u2234xy=x + yy + EC  xy+xEC=xy+y2  \u2234EC=y2x","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>46","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : LOCI","question":"Describe the locus L shown in the diagram below.","images":["data:image/png;base64,"],"options":{"A":"Locus of points equidistant from X and Y","B":"Locus of points equidistant from X and Z","C":"Locus of points equidistant from  ZX  and  ZY","D":"Locus of points equidistant from  XY  and  ZY"},"answer":"C","explanation":"\u2220XZL = \u2220YZL  \u2234  ZL  is the bisector of \u2220XZY  \u2234  ZL  is the locus of points equidistant from  ZX  and  ZY","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>47","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Which of the following statements is true from the diagram below?","images":["data:image/png;base64,"],"options":{"A":"m + n = 90o","B":"m = n","C":"n > 45o","D":"m o"},"answer":"A","explanation":"m + m = 180o - (n + n) (alternate angles and angle on a straight line)  2m = 180o - 2n  2m + 2n = 180o  2(m + n) = 180o  \u2234 m + n = 90o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>48","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, O is the centre of the circle. \u2220PQR = 75o, \u2220OPS = yo and  OR  is parallel to  PS . Find y.","images":["data:image/png;base64,"],"options":{"A":"15o","B":"30o","C":"45o","D":"75o"},"answer":"B","explanation":"\u2220POR = 2\u2220PQR (angle at centre is twice the angle subtends at circumference)  \u2220POR = 2 x 75o = 150o  \u2220AOP = 180o - 150o (sum of angles on a straight line)  \u2220AOP = y (alternate angles are equal)  \u2234 y = 30o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1999>49","subject":"Mathematics","year":"1999","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"The sides of a right angle triangle, in ascending order are 8 cm, (x - 2) cm, and x cm. Find x.","images":[],"options":{"A":"16 cm","B":"17 cm","C":"34 cm","D":"60 cm"},"answer":"B","explanation":"x = hypotenuse  8 and (x - 2) are the other two sides.  Using pythagoras theorem  x2 = (x - 2)2 + 82  x2 = x2 - 4x + 4 + 64  x2 - x2 + 4x = 68  4x = 68  \u2234 x = 17 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1999>50","subject":"Mathematics","year":"1999","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram, CDE is a triangle, ABEF is a cyclic quadrilateral, AB||CD, \u2220BAF = 65o and \u2220AFE = 85o. Calculate \u2220CDE.","images":["data:image/png;base64,"],"options":{"A":"20o","B":"30o","C":"50o","D":"65o"},"answer":"B","explanation":"Let the point where AB meets FD = x  \u2234 \u2220FXA = \u2220CDE (corresponding angles)  But \u2220BAF + \u2220AFE + \u2220EXB = 180o (sum of angles in a triangle)  65o + 85o + \u2220FXA = 180o  150o + \u2220FXA = 180o  \u2220FXA = 180o - 150o  \u2234 \u2220FXA = 30o","marks":"1","difficulty":"3"}];